import{_ as n,o as a,c as p,a0 as e}from"./chunks/framework.DgPozsi0.js";const o=JSON.parse('{"title":"[Next.js官網] Next.js 16.2 教程","description":"","frontmatter":{"title":"[Next.js官網] Next.js 16.2 教程"},"headers":[],"relativePath":"pages/f2e/docReact/nextDev/01/nextDev_01_15.md","filePath":"pages/f2e/docReact/nextDev/01/nextDev_01_15.md"}'),l={name:"pages/f2e/docReact/nextDev/01/nextDev_01_15.md"};function i(r,s,c,b,t,m){return a(),p("div",null,[...s[0]||(s[0]=[e(`<h1 id="加入中繼資料" tabindex="-1">加入中繼資料 <a class="header-anchor" href="#加入中繼資料" aria-label="Permalink to &quot;加入中繼資料&quot;">​</a></h1><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>中繼資料（Metadata）對於 SEO 與內容分享來說相當重要。在這一章中，我們將討論如何為你的 Next.js 應用程式加入中繼資料。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**本章內容**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>以下是本章將涵蓋的主題：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>什麼是中繼資料。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中繼資料的種類。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如何使用中繼資料加入 Open Graph 圖片。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如何使用中繼資料加入 favicon（網站圖示）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 什麼是中繼資料？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在網頁開發中，中繼資料提供了關於網頁的額外詳細資訊。造訪頁面的使用者並不會看到中繼資料，它是在幕後運作的，被嵌入在頁面的 HTML 中，通常會放在 \`&lt;head&gt;\` 元素內。這些隱藏的資訊，對於搜尋引擎以及其他需要更加理解你網頁內容的系統來說，是相當重要的。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 為什麼中繼資料很重要？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中繼資料在強化網頁 SEO 上扮演著相當重要的角色，能讓網頁對搜尋引擎與社群媒體平台來說更容易被存取與理解。適當的中繼資料，能幫助搜尋引擎有效地為網頁建立索引，進而提升網頁在搜尋結果中的排名。此外，像 Open Graph 這類的中繼資料，也能改善連結在社群媒體上被分享時的呈現方式，讓內容對使用者來說更具吸引力、資訊也更加完整。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 中繼資料的種類</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中繼資料有許多不同的種類，每一種都有其獨特的用途。一些常見的類型包括：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**標題中繼資料（Title Metadata）**：負責網頁的標題，會顯示在瀏覽器的分頁上。這對 SEO 來說相當重要，因為它能幫助搜尋引擎理解這個網頁的內容主題。</span></span>
<span class="line"><span>&lt;title&gt;Page Title&lt;/title&gt; \`\`\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>說明中繼資料（Description Metadata）：這種中繼資料提供了網頁內容的簡短概述，經常會顯示在搜尋引擎的結果中。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;meta name=&quot;description&quot; content=&quot;A brief description of the page content.&quot; /&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>關鍵字中繼資料（Keyword Metadata）：這種中繼資料包含了與網頁內容相關的關鍵字，能幫助搜尋引擎為頁面建立索引。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;meta name=&quot;keywords&quot; content=&quot;keyword1, keyword2, keyword3&quot; /&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Open Graph 中繼資料：這種中繼資料能強化網頁在社群媒體平台上被分享時的呈現方式，提供標題、說明與預覽圖片等資訊。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;meta property=&quot;og:title&quot; content=&quot;Title Here&quot; /&gt;</span></span>
<span class="line"><span>&lt;meta property=&quot;og:description&quot; content=&quot;Description Here&quot; /&gt;</span></span>
<span class="line"><span>&lt;meta property=&quot;og:image&quot; content=&quot;image_url_here&quot; /&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Favicon 中繼資料：這種中繼資料會將 favicon（一個小圖示）連結到網頁上，並顯示在瀏覽器的網址列或分頁上。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;link rel=&quot;icon&quot; href=&quot;path/to/favicon.ico&quot; /&gt;</span></span>
<span class="line"><span>加入中繼資料</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Next.js 具備一套 Metadata API，可以用來定義應用程式的中繼資料。你可以透過以下兩種方式，為你的應用程式加入中繼資料：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>以設定為基礎（Config-based）：在 layout.js 或 page.js 檔案中，匯出一個靜態的 metadata 物件，或是一個動態的generateMetadata 函式。</span></span>
<span class="line"><span>以檔案為基礎（File-based）：Next.js 提供了一系列專門用於中繼資料用途的特殊檔案：</span></span>
<span class="line"><span>favicon.ico、apple-icon.jpg 與 icon.jpg：用於 favicon 與各種圖示。</span></span>
<span class="line"><span>opengraph-image.jpg 與 twitter-image.jpg：用於社群媒體上顯示的圖片。</span></span>
<span class="line"><span>robots.txt：提供搜尋引擎爬蟲的爬取指示。</span></span>
<span class="line"><span>sitemap.xml：提供網站結構的相關資訊。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你可以彈性地使用這些檔案來設定靜態中繼資料，也可以在專案中以程式化的方式動態產生它們。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>無論使用上述哪一種方式，Next.js 都會自動為你的頁面產生相對應的 &lt;head&gt; 元素。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Favicon 與 Open Graph 圖片</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在你的 /public 資料夾中，你會注意到有兩張圖片：favicon.ico 與 opengraph-image.jpg。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>將這兩張圖片移動到你的 /app 資料夾根目錄下。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>完成這個步驟後，Next.js 就會自動識別並使用這些檔案，作為你的 favicon 與 OG 圖片。你可以在開發者工具中檢查應用程式的 &lt;head&gt; 元素，來確認這一點。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>小知識： 你也可以使用ImageResponse建構函式，動態產生 OG 圖片。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>頁面標題與說明</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你也可以在任何 layout.js 或 page.js 檔案中，加入一個metadata 物件，藉此加入額外的頁面資訊，例如標題與說明。任何在 layout.js 中定義的中繼資料，都會被使用該版面配置的所有頁面所繼承。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在你的根版面配置中，建立一個新的 metadata 物件，包含以下欄位：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/app/layout.tsx</span></span>
<span class="line"><span></span></span>
<span class="line"><span>import { Metadata } from &#39;next&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export const metadata: Metadata = {</span></span>
<span class="line"><span>  title: &#39;Acme Dashboard&#39;,</span></span>
<span class="line"><span>  description: &#39;The official Next.js Course Dashboard, built with App Router.&#39;,</span></span>
<span class="line"><span>  metadataBase: new URL(&#39;https://next-learn-dashboard.vercel.sh&#39;),</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export default function RootLayout() {</span></span>
<span class="line"><span>  // ...</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Next.js 會自動為你的應用程式加入標題與中繼資料。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不過，如果你想為某個特定頁面加入自訂標題，該怎麼做呢？你可以直接在該頁面中加入一個 metadata 物件來達成。巢狀頁面中的中繼資料，會覆蓋父層中的中繼資料設定。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>舉例來說，在 /dashboard/invoices 頁面中，你可以更新頁面標題：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/app/dashboard/invoices/page.tsx</span></span>
<span class="line"><span></span></span>
<span class="line"><span>import { Metadata } from &#39;next&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export const metadata: Metadata = {</span></span>
<span class="line"><span>  title: &#39;Invoices | Acme Dashboard&#39;,</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>這樣做雖然可行，但我們在每一個頁面中都重複輸入了應用程式的標題。如果有任何內容需要變更，例如公司名稱，你就得在每一個頁面中逐一更新。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>取而代之，你可以使用 metadata 物件中的 title.template 欄位，來定義頁面標題的樣板（template）。這個樣板可以包含頁面標題，以及任何你想加入的其他資訊。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在你的根版面配置中，更新 metadata 物件，加入一個樣板：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/app/layout.tsx</span></span>
<span class="line"><span></span></span>
<span class="line"><span>import { Metadata } from &#39;next&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export const metadata: Metadata = {</span></span>
<span class="line"><span>  title: {</span></span>
<span class="line"><span>    template: &#39;%s | Acme Dashboard&#39;,</span></span>
<span class="line"><span>    default: &#39;Acme Dashboard&#39;,</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  description: &#39;The official Next.js Learn Dashboard built with App Router.&#39;,</span></span>
<span class="line"><span>  metadataBase: new URL(&#39;https://next-learn-dashboard.vercel.sh&#39;),</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>樣板中的 %s 會被替換成該頁面特定的標題。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>現在，在你的 /dashboard/invoices 頁面中，你可以加入頁面標題：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/app/dashboard/invoices/page.tsx</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export const metadata: Metadata = {</span></span>
<span class="line"><span>  title: &#39;Invoices&#39;,</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>前往 /dashboard/invoices 頁面，檢查 &lt;head&gt; 元素。你應該會看到頁面標題現在變成了「Invoices | Acme Dashboard」。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>練習：加入中繼資料</span></span>
<span class="line"><span></span></span>
<span class="line"><span>現在你已經學會了中繼資料的相關知識，讓我們透過練習，為其他頁面加入標題：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/login 頁面。</span></span>
<span class="line"><span>/dashboard/ 頁面。</span></span>
<span class="line"><span>/dashboard/customers 頁面。</span></span>
<span class="line"><span>/dashboard/invoices/create 頁面。</span></span>
<span class="line"><span>/dashboard/invoices/[id]/edit 頁面。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Next.js 的 Metadata API 相當強大且具彈性，讓你能完全掌控應用程式的中繼資料。在這裡，我們示範了如何加入一些基本的中繼資料，不過你還可以加入更多欄位，包括 keywords、robots、canonical 等等。歡迎自由探索官方文件，為你的應用程式加入任何你需要的其他中繼資料。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你已完成第十五章</span></span>
<span class="line"><span></span></span>
<span class="line"><span>恭喜！你已經為應用程式加入了中繼資料，也認識了 Metadata API。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>下一步</span></span>
<span class="line"><span></span></span>
<span class="line"><span>16：後續步驟（Next Steps）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>繼續探索 Next.js。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>開始第十六章</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br><span class="line-number">58</span><br><span class="line-number">59</span><br><span class="line-number">60</span><br><span class="line-number">61</span><br><span class="line-number">62</span><br><span class="line-number">63</span><br><span class="line-number">64</span><br><span class="line-number">65</span><br><span class="line-number">66</span><br><span class="line-number">67</span><br><span class="line-number">68</span><br><span class="line-number">69</span><br><span class="line-number">70</span><br><span class="line-number">71</span><br><span class="line-number">72</span><br><span class="line-number">73</span><br><span class="line-number">74</span><br><span class="line-number">75</span><br><span class="line-number">76</span><br><span class="line-number">77</span><br><span class="line-number">78</span><br><span class="line-number">79</span><br><span class="line-number">80</span><br><span class="line-number">81</span><br><span class="line-number">82</span><br><span class="line-number">83</span><br><span class="line-number">84</span><br><span class="line-number">85</span><br><span class="line-number">86</span><br><span class="line-number">87</span><br><span class="line-number">88</span><br><span class="line-number">89</span><br><span class="line-number">90</span><br><span class="line-number">91</span><br><span class="line-number">92</span><br><span class="line-number">93</span><br><span class="line-number">94</span><br><span class="line-number">95</span><br><span class="line-number">96</span><br><span class="line-number">97</span><br><span class="line-number">98</span><br><span class="line-number">99</span><br><span class="line-number">100</span><br><span class="line-number">101</span><br><span class="line-number">102</span><br><span class="line-number">103</span><br><span class="line-number">104</span><br><span class="line-number">105</span><br><span class="line-number">106</span><br><span class="line-number">107</span><br><span class="line-number">108</span><br><span class="line-number">109</span><br><span class="line-number">110</span><br><span class="line-number">111</span><br><span class="line-number">112</span><br><span class="line-number">113</span><br><span class="line-number">114</span><br><span class="line-number">115</span><br><span class="line-number">116</span><br><span class="line-number">117</span><br><span class="line-number">118</span><br><span class="line-number">119</span><br><span class="line-number">120</span><br><span class="line-number">121</span><br><span class="line-number">122</span><br><span class="line-number">123</span><br><span class="line-number">124</span><br><span class="line-number">125</span><br><span class="line-number">126</span><br><span class="line-number">127</span><br><span class="line-number">128</span><br><span class="line-number">129</span><br><span class="line-number">130</span><br><span class="line-number">131</span><br><span class="line-number">132</span><br><span class="line-number">133</span><br><span class="line-number">134</span><br><span class="line-number">135</span><br><span class="line-number">136</span><br><span class="line-number">137</span><br><span class="line-number">138</span><br><span class="line-number">139</span><br><span class="line-number">140</span><br><span class="line-number">141</span><br><span class="line-number">142</span><br><span class="line-number">143</span><br><span class="line-number">144</span><br><span class="line-number">145</span><br><span class="line-number">146</span><br><span class="line-number">147</span><br><span class="line-number">148</span><br><span class="line-number">149</span><br><span class="line-number">150</span><br><span class="line-number">151</span><br><span class="line-number">152</span><br><span class="line-number">153</span><br><span class="line-number">154</span><br><span class="line-number">155</span><br><span class="line-number">156</span><br><span class="line-number">157</span><br><span class="line-number">158</span><br><span class="line-number">159</span><br></div></div>`,2)])])}const d=n(l,[["render",i]]);export{o as __pageData,d as default};
